import "../styles/UploadForm.css";
import { useState } from "react";
import ResultCard from "./ResultCard";
import { useDropzone } from "react-dropzone";

function UploadForm() {
  const [image, setImage] = useState(null);
  const [weight, setWeight] = useState("");
  const [cmPerPixel, setCmPerPixel] = useState("0.038");

  const [result, setResult] = useState(null);

  const [imagePreview, setImagePreview] = useState(null);

  const [error, setError] = useState("");

  const [loading, setLoading] = useState(false);

  const onDropImage = (acceptedFiles) => {
    const file = acceptedFiles[0];

    if (file) {
      setImage(file);
      setImagePreview(URL.createObjectURL(file));
      setError("");
      setResult(null);
    }
  };

  const { getRootProps, getInputProps } = useDropzone({
    onDrop: onDropImage,
    accept: {
      "image/*": [],
    },
    multiple: false,
  });

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!image) {
      setError("Please upload a fish image.");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const formData = new FormData();

      formData.append("image", image);
      formData.append("cm_per_pixel", cmPerPixel);

      const response = await fetch("http://127.0.0.1:8000/predict", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.detail || "Prediction failed");
      }

      setResult({
        predicted_weight_g: data.predicted_weight_g,

        length_cm: data.features.length_cm,
        thickness_cm: data.features.thickness_cm,
        perimeter_cm: data.features.perimeter_cm,
        area_cm2: data.features.area_cm2,
        volume_proxy_cm3: data.features.volume_proxy_cm3,

        generated_mask: data.generated_mask || null,
      });
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const removeImage = () => {
    setImage(null);
    setImagePreview(null);
    setResult(null);
    setError("");
  };

  return (
    <div className="container">
      <form onSubmit={handleSubmit}>

        <label>Upload Fish Image</label>

        <div {...getRootProps()} className="dropzone">
          <input {...getInputProps()} />

          <p>Drag & Drop Fish Image Here</p>
          <span>or click to browse</span>
        </div>

        <label>Camera Calibration (cm/pixel)</label>

        <input
          type="number"
          step="0.001"
          value={cmPerPixel}
          onChange={(e) => setCmPerPixel(e.target.value)}
        />

        <small className="input-hint">
          Example: 0.038 cm/pixel
        </small>

        <label>Actual Weight (Optional)</label>

        <input
          type="number"
          value={weight}
          placeholder="Enter actual weight in grams"
          onChange={(e) => setWeight(e.target.value)}
        />

        <div className="preview-container">
          {imagePreview && (
            <div className="preview-card">

              <h4>Fish Image</h4>

              <img
                src={imagePreview}
                alt="Fish"
              />

              <button
                type="button"
                className="remove-btn"
                onClick={removeImage}
              >
                Remove
              </button>

            </div>
          )}
        </div>

        {error && (
          <p className="error">
            {error}
          </p>
        )}

        <button type="submit">
          {loading ? "Estimating..." : "Estimate Weight"}
        </button>

      </form>

      <ResultCard result={result} />

    </div>
  );
}

export default UploadForm;
